 80→export const getChapterService = async (storyId, chapterId, userId) => {
 81→    if (!storyId || !chapterId) {
 82→        throw { status: 400, error: 'storyId and chapterId are required' };
 83→    }
 84→
 85→    // Fetch story to check privacy
 86→    const { data: story, error: storyError } = await supabase
 87→        .from('stories')
 88→        .select('author_id, privacy')
 89→        .eq('id', storyId)
 90→        .single();
 91→
 92→    if (storyError || !story) {
 93→        throw { status: 404, error: 'story not found' };
 94→    }
 95→
 96→    const isAuthor = story.author_id === userId;
 97→    if (story.privacy === 'private' && !isAuthor) {
 98→        throw { status: 404, error: 'story not found' };
 99→    }
100→
101→    const { data: chapter, error } = await supabase
102→        .from('chapters')
103→        .select('*')
104→        .eq('id', chapterId)
105→        .eq('story_id', storyId)
106→        .single();
