### 12. **Mutation Patterns** (`client/src/utils/useMutation.js`)

**`useLikeMutation` Structure:**
```javascript
export const useLikeMutation = (session, userId) => {
    const queryClient = useQueryClient();
    const inFlightLikeIdsRef = useRef(new Set());

    const mutation = useMutation({
        mutationFn: (data) => clickLike(session?.access_token, data),

        onMutate: async(data) => {
            // Cancel ongoing queries
            queryClient.cancelQueries({ queryKey: ['journals'] });
            queryClient.cancelQueries({ queryKey: ['userJournals'] });
            queryClient.cancelQueries({ queryKey: ['visitedProfileJournals'] });

            // Update cache optimistically
            const updater = (journal) => {
                if(journal.id !== data.journalId) return journal;

                const isLiked = normalizeInteractionFlag(journal?.has_liked);
                const count = normalizeCount(journal?.like_count?.[0]?.count);
                const nextCount = getNextToggleCount(isLiked, count);

                return {
                    ...journal,
                    has_liked: !isLiked,
                    like_count: [{count: nextCount}]
                };
            };

            queryClient.setQueriesData({ queryKey: ['journals'] }, 
                (old) => updateInfiniteJournalsCache(old, updater));
            // ... same for other query keys

            return {previousData};
        },

        onError: (err, data, context) => {
            // Rollback on error
            context?.previousData?.forEach(([key, value]) => {
                queryClient.setQueryData(key, value);
            });
        },

        onSettled: () => {
            // Invalidate to refetch fresh data
            queryClient.invalidateQueries({ queryKey: ['journals'] });
            queryClient.invalidateQueries({ queryKey: ['userJournals'] });
            queryClient.invalidateQueries({ queryKey: ['visitedProfileJournals'] });
        }
    });

    // Guard against duplicate mutations
    const guardedMutate = (variables, options) => {
        const journalKey = toJournalKey(variables?.journalId);
        if(journalKey && inFlightLikeIdsRef.current.has(journalKey)) return;

        if(journalKey) inFlightLikeIdsRef.current.add(journalKey);

        mutation.mutate(variables, {
            ...options,
            onSettled: (data, error, vars, context) => {
                if(journalKey) inFlightLikeIdsRef.current.delete(journalKey);
                options?.onSettled?.(data, error, vars, context);
            }
        });
    };

    return { ...mutation, mutate: guardedMutate };
};
```

**Key Features:**
- Optimistic updates across multiple query keys (journals, userJournals, visitedProfileJournals)
- In-flight deduplication via `Set`
- Normalization helpers for flexible data types
- Automatic cache invalidation on settled
- Rollback on error

